    /// <summary>
    /// Gets the ordered physical key geometry for a model slug and variant.
    /// Returns <see langword="false"/> (and an empty list) when no geometry has
    /// been defined for this model+variant yet.
    /// </summary>
    public static bool TryGetKeys(string modelSlug, string variant, out IReadOnlyList<KeyInfo> keys)
    {
        keys = (modelSlug, variant) switch
        {
            (ModelSlugs.A75Master, "ansi") => A75MasterAnsi,
            (ModelSlugs.A75, "ansi") or (ModelSlugs.A75, "ansi_alt") or (ModelSlugs.A75Ultra, "ansi") or (ModelSlugs.A75Ultra, "ansi_alt") or (ModelSlugs.A75Pro, "ansi") or (ModelSlugs.A75Pro, "ansi_alt") => A75Ansi,
            (ModelSlugs.G60, "ansi") or (ModelSlugs.G60V600, "ansi") => G60Ansi,
            (ModelSlugs.G65, "ansi") or (ModelSlugs.G65, "ansi_alt") or (ModelSlugs.G65Lite, "ansi") or (ModelSlugs.G65Lite, "ansi_alt") or (ModelSlugs.G65M1, "ansi") or (ModelSlugs.G65M1, "ansi_alt") or (ModelSlugs.G65M2, "ansi") or (ModelSlugs.G65M2, "ansi_alt") or (ModelSlugs.G65M3, "ansi") or (ModelSlugs.G65M3, "ansi_alt") => G65Ansi,
            (ModelSlugs.G75, "ansi") => G75Ansi,
            _ => System.Array.Empty<KeyInfo>(),
        };
        return keys.Count > 0;
    }
